<template>
  <view class="filter-bar">
    <view class="filter-item" @click="openPopup">
      <text class="filter-text">{{ diseaseText }}</text>
      <u-icon name="arrow-down" size="12" color="#909399" />
    </view>

    <view class="filter-item" @click="openPopup">
      <text class="filter-text">{{ regionText }}</text>
      <u-icon name="arrow-down" size="12" color="#909399" />
    </view>

    <view class="filter-item" @click="openPopup">
      <text class="filter-text">{{ titleText }}</text>
      <u-icon name="arrow-down" size="12" color="#909399" />
    </view>

    <view class="filter-item" @click="openPopup">
      <text class="filter-text">{{ hospitalText }}</text>
      <u-icon name="arrow-down" size="12" color="#909399" />
    </view>

    <FilterPopup
      v-model:show="showPopup"
      v-model="localValue"
      @confirm="handleConfirm"
      @reset="handleReset"
    />
  </view>
</template>

<script setup lang="ts">
import { computed, ref, watch } from 'vue'
import FilterPopup, { type FilterForm } from './FilterPopup.vue'

const props = withDefaults(defineProps<{
  modelValue?: Partial<FilterForm>
}>(), {
  modelValue: () => ({})
})

const emit = defineEmits<{
  (e: 'update:modelValue', value: FilterForm): void
  (e: 'change', value: FilterForm): void
  (e: 'reset'): void
}>()

const showPopup = ref(false)
const localValue = ref<FilterForm>({
  diseaseId: '',
  diseaseName: '',
  title: '',
  region: {},
  hospital: {}
})

watch(
  () => props.modelValue,
  (val) => {
    localValue.value = {
      diseaseId: val?.diseaseId || '',
      diseaseName: val?.diseaseName || '',
      title: val?.title || '',
      region: val?.region || {},
      hospital: val?.hospital || {}
    }
  },
  { immediate: true, deep: true }
)

const diseaseText = computed(() => localValue.value.diseaseName || '病种')
const titleText = computed(() => localValue.value.title || '职称')
const hospitalText = computed(() => localValue.value.hospital?.hospitalName || '医院')
const regionText = computed(() => {
  const region = localValue.value.region || {}
  return region.districtName || region.cityName || region.provinceName || '地区'
})

const openPopup = () => {
  showPopup.value = true
}

const handleConfirm = (value: FilterForm) => {
  localValue.value = value
  emit('update:modelValue', value)
  emit('change', value)
}

const handleReset = () => {
  localValue.value = {
    diseaseId: '',
    diseaseName: '',
    title: '',
    region: {},
    hospital: {}
  }
  emit('update:modelValue', localValue.value)
  emit('reset')
}
</script>

